import{_ as e,c as l,o as t,ag as r}from"./chunks/framework.DPDPlp3K.js";const p=JSON.parse('{"title":"绘图软件","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/必备技能/grace&gnuplot.md","filePath":"分子模拟/必备技能/grace&gnuplot.md","lastUpdated":null}'),i={name:"分子模拟/必备技能/grace&gnuplot.md"};function o(n,a,c,u,d,s){return t(),l("div",null,a[0]||(a[0]=[r('<h1 id="绘图软件" tabindex="-1">绘图软件 <a class="header-anchor" href="#绘图软件" aria-label="Permalink to &quot;绘图软件&quot;">​</a></h1><blockquote><p>介绍一些可以在Linux系统运行的图表绘制软件</p></blockquote><h2 id="grace" tabindex="-1">Grace <a class="header-anchor" href="#grace" aria-label="Permalink to &quot;Grace&quot;">​</a></h2><ul><li><strong>Grace</strong>：是“GRaphing, Advanced Computation and Exploration of data”的缩写，它是一款在X Window系统和Motif下的所见即所得（WYSIWYG）的二维绘图软件。Grace可以运行在任何类Unix系统操作系统下，包括OpenVMS、OS/2和Microsoft Windows（通过Cygwin）</li><li><strong>xmgrace</strong>：在Linux环境下，特别是Ubuntu等发行版中，Grace通常被称为xmgrace，这是因为它是作为X Window系统下的一个应用程序而存在的。xmgrace是Linux下类似origin的免费开源画图软件，它继承了Grace的所有绘图功能，并且针对Linux环境进行了优化。</li><li>QtGrace：基于Qt的Grace，QtGrace和xmgrace用法基本没区别，而前者界面显得更现代，用着更舒服，还做了额外的扩展。QtGrace是为了在Windows系统上提供与xmgrace相似的绘图体验而开发的，它利用QT的跨平台特性，使得Windows用户也能方便地使用与xmgrace相似的绘图功能。</li><li>#免费 #开源 #跨平台</li><li>官网：<a href="https://plasma-gate.weizmann.ac.il/Grace/" target="_blank" rel="noreferrer">Grace Home (weizmann.ac.il)</a></li></ul><h3 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h3><ul><li>按下 ctrl+L，就可以移动lengend</li><li>双击边框即可调整图表大小</li><li>双击曲线即可调整曲线样式</li><li>保存: 选择好要保存的路径和名称，以 .agr结尾。</li></ul><h2 id="gnuplot" tabindex="-1">gnuplot <a class="header-anchor" href="#gnuplot" aria-label="Permalink to &quot;gnuplot&quot;">​</a></h2><ul><li>介绍：Gnuplot 是一个可移植的命令行驱动的图形实用程序，可视化数学函数和数据，也被 Octave 等第三方应用程序用作绘图引擎。Gnuplot 支持许多不同类型的 2D 和 3D 绘图</li><li>#开源 #免费 #跨平台</li><li>官网：<a href="http://www.gnuplot.info/" target="_blank" rel="noreferrer">gnuplot homepage</a></li></ul><h2 id="labplot" tabindex="-1">LabPlot <a class="header-anchor" href="#labplot" aria-label="Permalink to &quot;LabPlot&quot;">​</a></h2><ul><li>简介：开源和跨平台的数据可视化和分析软件, 有图形化界面, 类似于Windows的Origin</li><li>#开源 #免费 #跨平台</li><li>官网：<a href="https://labplot.kde.org/" target="_blank" rel="noreferrer">LabPlot – Scientific plotting and data analysis</a></li></ul>',10)]))}const h=e(i,[["render",o]]);export{p as __pageData,h as default};
